fn apply_controller_events(&mut self) {
    let events = self.controller.drain_events();
    if events.is_empty() {
        return;
    }
    for event in events {
        match event {
            WorkLeafEvent::AgentAdded { session } | WorkLeafEvent::AgentUpdated { session } => {
                self.upsert_cached_session(session.clone());
                self.apply_session_to_ui(&session);
            }
            WorkLeafEvent::AgentStatusUpdated {
                agent_id,
                kind,
                title,
                feature,
                loading,
            } => {
                let session =
                    self.upsert_cached_session_status(agent_id, kind, title, feature, loading);
                self.apply_session_to_ui(&session);
            }
            WorkLeafEvent::AgentLineAppended { agent_id, line } => {
                if line == FEATURE_DONE_PROMPT {
                    self.feature_done_confirmations.insert(agent_id.clone());
                    let _ = self.ui.show_agent(&agent_id);
                }
                self.append_cached_agent_line(&agent_id, line);
            }
            WorkLeafEvent::AgentSelected { agent_id } => {
                let _ = self.ui.activate_agent_chat(&agent_id);
            }
            WorkLeafEvent::CommandTranscriptLine { line } => {
                self.snapshot.command_transcript.push(line);
            }
            WorkLeafEvent::QuitRequested => {
                self.quit = true;
            }
        }
    }
    self.dirty = true;
}

fn upsert_cached_session(&mut self, session: WorkLeafSession) {
    if let Some(existing) = self
        .snapshot
        .sessions
        .iter_mut()
        .find(|existing| existing.id == session.id)
    {
        *existing = session;
    } else {
        self.snapshot.sessions.push(session);
        self.snapshot
            .sessions
            .sort_by(|left, right| left.id.as_str().cmp(right.id.as_str()));
    }
}

fn upsert_cached_session_status(
    &mut self,
    agent_id: AgentId,
    kind: crate::agent::AgentKind,
    title: String,
    feature: String,
    loading: Option<WorkLeafLoading>,
) -> WorkLeafSession {
    if let Some(session) = self
        .snapshot
        .sessions
        .iter_mut()
        .find(|session| session.id == agent_id)
    {
        session.kind = kind;
        session.title = title;
        session.feature = feature;
        session.loading = loading;
        return session.clone();
    }

    let session = WorkLeafSession {
        id: agent_id,
        kind,
        title,
        feature,
        lines: Vec::new(),
        loading,
    };
    self.snapshot.sessions.push(session.clone());
    self.snapshot
        .sessions
        .sort_by(|left, right| left.id.as_str().cmp(right.id.as_str()));
    session
}

fn append_cached_agent_line(&mut self, agent_id: &AgentId, line: String) {
    if line.is_empty() {
        return;
    }
    let Some(session) = self
        .snapshot
        .sessions
        .iter_mut()
        .find(|session| &session.id == agent_id)
    else {
        return;
    };
    if line == FEATURE_DONE_PROMPT || !session.lines.iter().any(|existing| existing == &line) {
        session.lines.push(line);
    }
}

fn apply_session_to_ui(&mut self, session: &WorkLeafSession) {
    if self
        .ui
        .set_agent_feature(&session.id, session.title.clone())
        .is_err()
    {
        self.ui.add_agent(AgentListEntry::new(
            session.id.clone(),
            session.title.clone(),
        ));
    }
    let _ = self
        .ui
        .set_agent_ready_state(&session.id, session.loading.is_none());
}

fn apply_session_feature_done_state(&mut self, session: &WorkLeafSession) {
    if session
        .lines
        .iter()
        .rev()
        .any(|line| line == FEATURE_DONE_PROMPT)
    {
        self.feature_done_confirmations.insert(session.id.clone());
    }
}

fn handle_feature_done_confirmation(&mut self, agent_id: &AgentId, message: &str) -> bool {
    if !self.feature_done_confirmations.remove(agent_id) {
        return false;
    }

    if message.eq_ignore_ascii_case("yes") {
        let _ = self.ui.hide_agent(agent_id);
        return true;
    }

    let _ = self.ui.show_agent(agent_id);
    message.eq_ignore_ascii_case("no")
}

